{"code":"import json
import re

file_path = locals()['var_function-call-4070202072928097039']
with open(file_path, 'r') as f:
    citing_patents = json.load(f)

print(f"Loaded {len(citing_patents)} citing patents.")

results = []
subclasses = set()

# Regex for assignee
# "is assigned to X and", "is held by X and", "is owned by X and", "is belonging to X and", "X holds the"
assignee_regexes = [
    re.compile(r'is assigned to (.+?) and', re.IGNORECASE),
    re.compile(r'is held by (.+?) and', re.IGNORECASE),
    re.compile(r'is owned by (.+?) and', re.IGNORECASE),
    re.compile(r'is belonging to (.+?) and', re.IGNORECASE),
    re.compile(r'(.+?) holds the', re.IGNORECASE)
]

def extract_assignee(text):
    for r in assignee_regexes:
        m = r.search(text)
        if m:
            return m.group(1).strip()
    return None

def extract_subclass(cpc_json):
    try:
        cpc_list = json.loads(cpc_json)
        # Find first: true
        primary = next((item for item in cpc_list if item.get('first')), None)
        if not primary and cpc_list:
            primary = cpc_list[0]

        if primary:
            code = primary.get('code', '')
            # Subclass is first 4 chars, e.g., G01V
            if len(code) >= 4:
                return code[:4]
    except:
        pass
    return None

for row in citing_patents:
    assignee = extract_assignee(row.get('Patents_info', ''))
    subclass = extract_subclass(row.get('cpc', '[]'))

    if assignee and subclass:
        # Exclude UNIV CALIFORNIA just in case regex captured it (e.g. "UNIV CALIFORNIA holds...")
        if "UNIV CALIFORNIA" not in assignee:
            results.append({"assignee": assignee, "subclass": subclass})
            subclasses.add(subclass)

print(f"Found {len(results)} citing assignee-subclass pairs.")
print(f"Found {len(subclasses)} unique subclasses.")
print(list(subclasses)[:5])

output = {
    "pairs": results,
    "subclasses": list(subclasses)
}

print("__RESULT__:")
print(json.dumps(output))
"}

